@RestController
@RequestMapping("/api/profile-pictures")
class ProfilePictureController {

    private static final Path UPLOAD_DIR = Paths.get("public/uploads/profile-pictures");
    private static final Set<String> ALLOWED_EXTENSIONS = Set.of("jpg", "jpeg", "png", "gif", "webp");
    private static final Set<String> ALLOWED_CONTENT_TYPES = Set.of(
            "image/jpeg",
            "image/png",
            "image/gif",
            "image/webp"
    );

    @PostMapping(value = "/upload", consumes = MediaType.MULTIPART_FORM_DATA_VALUE)
    public ResponseEntity<?> uploadProfilePicture(@RequestParam("file") MultipartFile file, HttpServletRequest request) {
        try {
            if (file == null || file.isEmpty()) {
                return ResponseEntity.badRequest().body(error("File is required"));
            }

            String originalFilename = StringUtils.cleanPath(file.getOriginalFilename() == null ? "" : file.getOriginalFilename());
            String extension = getExtension(originalFilename);

            if (!ALLOWED_EXTENSIONS.contains(extension)) {
                return ResponseEntity.status(HttpStatus.UNSUPPORTED_MEDIA_TYPE)
                        .body(error("Only image files are allowed: jpg, jpeg, png, gif, webp"));
            }

            String contentType = file.getContentType();
            if (contentType == null || !ALLOWED_CONTENT_TYPES.contains(contentType.toLowerCase(Locale.ROOT))) {
                return ResponseEntity.status(HttpStatus.UNSUPPORTED_MEDIA_TYPE)
                        .body(error("Invalid image content type"));
            }

            Files.createDirectories(UPLOAD_DIR);

            String filename = Instant.now().toEpochMilli() + "-" + UUID.randomUUID() + "." + extension;
            Path target = UPLOAD_DIR.resolve(filename).normalize();

            if (!target.startsWith(UPLOAD_DIR.normalize())) {
                return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(error("Invalid file path"));
            }

            try (InputStream inputStream = file.getInputStream()) {
                Files.copy(inputStream, target, StandardCopyOption.REPLACE_EXISTING);
            }

            String fileUrl = buildFileUrl(request, filename);

            Map<String, Object> response = new HashMap<>();
            response.put("message", "Upload successful");
            response.put("fileName", filename);
            response.put("url", fileUrl);
            response.put("contentType", contentType);

            return ResponseEntity.ok(response);
        } catch (IOException e) {
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(error("Failed to upload file"));
        }
    }

    private String getExtension(String filename) {
        int lastDot = filename.lastIndexOf('.');
        if (lastDot == -1 || lastDot == filename.length() - 1) {
            return "";
        }
        return filename.substring(lastDot + 1).toLowerCase(Locale.ROOT);
    }

    private String buildFileUrl(HttpServletRequest request, String filename) {
        String scheme = request.getScheme();
        String serverName = request.getServerName();
        int serverPort = request.getServerPort();
        String contextPath = request.getContextPath();

        String baseUrl = scheme + "://" + serverName +
                ((serverPort == 80 || serverPort == 443) ? "" : ":" + serverPort) +
                contextPath;

        return baseUrl + "/uploads/profile-pictures/" + filename;
    }

    private Map<String, String> error(String message) {
        Map<String, String> error = new HashMap<>();
        error.put("error", message);
        return error;
    }
}

package com.example.profileupload;

import org.springframework.context.annotation.Configuration;
import org.springframework.web.servlet.config.annotation.EnableWebMvc;
import org.springframework.web.servlet.config.annotation.ResourceHandlerRegistry;
import org.springframework.web.servlet.config.annotation.WebMvcConfigurer;

import java.nio.file.Path;
import java.nio.file.Paths;

@Configuration
@EnableWebMvc
class StaticResourceConfig implements WebMvcConfigurer {

    @Override
    public void addResourceHandlers(ResourceHandlerRegistry registry) {
        Path publicDir = Paths.get("public").toAbsolutePath().normalize();
        registry.addResourceHandler("/uploads/**")
                .addResourceLocations("file:" + publicDir.toString() + "/uploads/");
    }
}